def parse(
    text: str,
    *,
    filename: str = "",
    hooks: HookRegistry | None = None,
    token_filter: TokenFilter | None = None,
) -> AstNode:
    """Parse ``text`` against the embedded c23 grammar.

    ``filename`` is interned into :data:`FILE_TABLE` and stamped as
    ``file_id`` on every emitted Token. Decode back to the filename
    via ``FILE_TABLE.name(token.file_id)``.

    Returns the typed AST root produced by the grammar's
    annotations. Raises :class:`uplox.parse.runtime.ParseError`
    on a syntax error.

    Hosts that want the raw parse tree should call
    :func:`parse_cst` instead.
    """
    file_id = FILE_TABLE.intern(filename)
    return _runtime_parse(
        _table,
        _scanner.scan(text, file_id=file_id),
        hooks=hooks or HookRegistry(ignore_missing=True),
        semantic_actions=_AST_ACTIONS,
        token_filter=token_filter,
    )


def parse_cst(
    text: str,
    *,
    filename: str = "",
    hooks: HookRegistry | None = None,
    token_filter: TokenFilter | None = None,
) -> StackValue:
    """Parse ``text`` and return the raw parse tree (CST).

    ``filename`` is interned into :data:`FILE_TABLE` and stamped as
    ``file_id`` on every emitted Token.

    Useful for editor integrations or debug viewers that want
    the concrete-syntax shape rather than the AST.
    """
    file_id = FILE_TABLE.intern(filename)
    return _runtime_parse(
        _table,
        _scanner.scan(text, file_id=file_id),
        hooks=hooks or HookRegistry(ignore_missing=True),
        token_filter=token_filter,
    )


def scan(text: str, *, filename: str = "") -> Iterable[Token]:
    """Run only the lexer on ``text`` and yield tokens. ``filename``
    is interned and stamped on each Token as ``file_id``."""
    file_id = FILE_TABLE.intern(filename)
    return _scanner.scan(text, file_id=file_id)

